import{_ as s,o as r,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"11. Transfer Of Business","description":"","frontmatter":{"title":"11. Transfer Of Business","eba":"Allied Health Professionals 2021-2026","topics":["employment"]},"headers":[],"relativePath":"ebas/allied-health/preliminary/11-transfer-of-business.md","filePath":"ebas/allied-health/preliminary/11-transfer-of-business.md"}'),t={name:"ebas/allied-health/preliminary/11-transfer-of-business.md"};function o(i,e,l,f,h,p){return r(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="_11-transfer-of-business" tabindex="-1">11. Transfer Of Business <a class="header-anchor" href="#_11-transfer-of-business" aria-label="Permalink to &quot;11. Transfer Of Business&quot;">​</a></h1><p><strong>11.1</strong> Where the business of the employer is, before or after the date of the Agreement, transferred from the employer (in this clause 11 called the Transferor) to another employer (in this clause 11 called the Transferee) and an employee who at the time of such transfer was an employee of the Transferor in that business becomes an employee of the Transferee:</p><p><strong>(a)</strong> the continuity of the employment of the employee will be deemed not to have been broken by reason of such transfer; and</p><p><strong>(b)</strong> the period of employment which the employee has had with the Transferor or any prior transferor will be deemed to be service of the employee with the Transferee; save that where the Transferor pays out accrued annual leave and/or long service leave to the employee upon the employee ceasing to be employed by them, this accrued annual leave and/or long service leave is not transferred to the Transferee.</p><p><strong>11.2</strong> In this clause 11:</p><p><strong>(a)</strong> business includes trade, process, business or occupation and includes any part of any such business; and</p><p><strong>(b)</strong> transfer includes transmission, conveyance, assignment or succession whether by agreement or by operation of law and transferred has a corresponding meaning.</p>',7)])])}const m=s(t,[["render",o]]);export{d as __pageData,m as default};
